          url: "https://doi.org/10.1002/xrs.2759",
          volume: "46",
          author:
            "Gonçalves, E. A. S. and Oliveira, D. F. and Anjos, M. J. and Assis, J. T. and Oliveira, L. F. and Lopes, R. T.",
